{
  "uiTreePath": ".arkpilot/designs/ui-tree.json",
  "version": "arkpilot-a2ui/v2-behavior",
  "appName": "平安扣 Pinankou",
  "headlessPhase": "logic-only; visual integration deferred until design-alignment/page-*.html arrive",
  "dataModel": {
    "entities": {
      "SafetyItem": {
        "fields": {
          "id": "string",
          "title": "string",
          "description": "string",
          "level": "SafetyLevel(low|medium|high)",
          "owner": "string",
          "completed": "boolean",
          "createdAt": "number",
          "updatedAt": "number"
        },
        "persistence": "durable-local"
      },
      "Hazard": {
        "fields": {
          "id": "string",
          "title": "string",
          "description": "string",
          "level": "SafetyLevel",
          "location": "string",
          "photoUri": "string",
          "owner": "string",
          "deadline": "number",
          "status": "HazardStatus(pending|in_progress|rectified|overdue)",
          "note": "string",
          "createdAt": "number",
          "updatedAt": "number"
        },
        "persistence": "durable-local",
        "derivedStatus": "overdue computed when deadline<now and status!=rectified"
      },
      "PatrolPoint": {
        "fields": {
          "id": "string",
          "name": "string",
          "location": "string",
          "status": "PatrolPointStatus(pending|checked|abnormal)",
          "checkedAt": "number"
        }
      },
      "PatrolTask": {
        "fields": {
          "id": "string",
          "title": "string",
          "points": "PatrolPoint[]",
          "createdAt": "number"
        },
        "persistence": "durable-local"
      },
      "EmergencyContact": {
        "fields": {
          "id": "string",
          "name": "string",
          "phone": "string",
          "role": "string"
        },
        "persistence": "durable-local"
      }
    },
    "computedState": {
      "todayTodoCount": "count of SafetyItem where completed=false and createdAt is today OR owner-unassigned; approximated as incomplete safety items",
      "hazardCount": "count of Hazard where status!=rectified",
      "rectifyRate": "round(rectified / totalHazards * 100)",
      "patrolRate": "round(checkedPoints / totalPoints across all tasks * 100)",
      "recentSafetyItems": "SafetyItem[] sorted by updatedAt desc, top 5"
    },
    "formState": {
      "safetyFilter": "all|pending|completed",
      "safetySearch": "string",
      "hazardFilter": "all|pending|in_progress|rectified|overdue",
      "contactSearch": "string",
      "patrolDraft": "{ title: string, points: PatrolPoint[] }"
    }
  },
  "services": {
    "DataStore": {
      "role": "single reactive in-memory repository backed by AppStorage; per-domain CRUD + array replacement",
      "storeKeys": ["pinankou.safety", "pinankou.hazards", "pinankou.patrol", "pinankou.contacts"]
    },
    "PersistenceService": {
      "role": "local durability via @ohos.data.preferences; serialize/deserialize each collection to JSON",
      "init": "PersistenceService.init(context) wires ability context; safe no-op fallback until wired",
      "fallback": "best-effort; failures logged, never crash UI"
    },
    "CallService": {
      "role": "trigger system dial intent via want action=ohos.want.action.callData / call phone",
      "fallback": "on real device dials number; documented stub returns intent params in headless phase"
    },
    "PhotoService": {
      "role": "capture/select hazard photo local URI; headless phase stores placeholder URI string, real picker wired in visual integration"
    }
  },
  "stateMachine": {
    "Hazard": {
      "states": ["pending", "in_progress", "rectified", "overdue"],
      "transitions": [
        "pending -> in_progress (owner starts rectification)",
        "in_progress -> rectified (status picker set to rectified)",
        "* -> overdue (derived: deadline<now and status!=rectified)",
        "rectified is terminal unless re-edited"
      ]
    },
    "PatrolPoint": {
      "states": ["pending", "checked", "abnormal"],
      "transitions": [
        "pending -> checked (checkin-patrol-point, status ok)",
        "pending -> abnormal (checkin with abnormal flag -> also seeds a Hazard)",
        "checked/abnormal are terminal for that point"
      ]
    },
    "SafetyItem": {
      "states": ["incomplete", "completed"],
      "transitions": ["toggle completed via safety-detail-status-toggle"]
    }
  },
  "interactionFlows": [
    {
      "flow": "create-safety-item",
      "triggers": ["navigate-to-add-safety", "open-add-safety-sheet"],
      "steps": [
        "open SafetyDetail page in create mode (empty draft)",
        "bind safety-detail-title-input/level-picker/owner-input/status-toggle",
        "on save-safety: validate title non-empty -> persist SafetyItem -> return to list"
      ],
      "errorPath": "empty title blocks save with feedback"
    },
    {
      "flow": "filter-search-safety",
      "triggers": ["change-safety-filter", "search-safety"],
      "steps": ["update safetyFilter/safetySearch", "recompute filtered list (filter by status + substring match on title/description/owner)"]
    },
    {
      "flow": "report-hazard",
      "triggers": ["navigate-to-add-hazard", "open-add-hazard-sheet", "pick-hazard-photo", "save-hazard"],
      "steps": [
        "open HazardDetail create mode",
        "capture title/description/level/location/owner/deadline/photoUri",
        "on save-hazard: validate title -> status=pending, createdAt/updatedAt=now -> persist"
      ]
    },
    {
      "flow": "track-rectification",
      "triggers": ["navigate-to-rectify", "change-hazard-filter", "save-hazard"],
      "steps": ["Hazards page lists hazards grouped/filtered by status", "HazardDetail status-picker updates status + note", "overdue auto-derived"]
    },
    {
      "flow": "patrol-checkin",
      "triggers": ["navigate-to-create-patrol", "add-patrol-point", "save-patrol-task", "checkin-patrol-point"],
      "steps": [
        "PatrolCreate builds draft task + points",
        "save-patrol-task persists PatrolTask",
        "Patrol page checkin button marks point checked (or abnormal -> seeds Hazard)"
      ]
    },
    {
      "flow": "manage-contact",
      "triggers": ["open-add-contact-sheet", "search-contacts", "call-contact", "save-contact", "delete-contact"],
      "steps": ["Contacts CRUD", "call-contact emits dial want with phone", "search filters by name/phone/role"]
    },
    {
      "flow": "dashboard-aggregate",
      "triggers": ["(data change)"],
      "steps": ["DashboardController computes todayTodoCount/hazardCount/rectifyRate/patrolRate/recentSafetyItems from stores"],
      "expectedState": "assertion targets dashboard-today-todo-count etc. reflect live aggregates"
    }
  ],
  "testTargets": {
    "dashboard": ["dashboard-add-safety-button", "dashboard-start-patrol-button", "dashboard-report-hazard-button", "dashboard-view-rectify-button", "dashboard-today-todo-count", "dashboard-hazard-count", "dashboard-rectify-rate", "dashboard-patrol-rate", "dashboard-recent-safety-list"],
    "safety": ["safety-add-button", "safety-filter-segment", "safety-search-input", "safety-item-list"],
    "safetyDetail": ["safety-detail-title-input", "safety-detail-level-picker", "safety-detail-owner-input", "safety-detail-status-toggle", "safety-detail-save-button", "safety-detail-delete-button"],
    "patrol": ["patrol-create-button", "patrol-task-list", "patrol-active-checkin-button"],
    "patrolCreate": ["patrol-create-title-input", "patrol-create-add-point-button", "patrol-create-point-list", "patrol-create-save-button"],
    "hazards": ["hazards-add-button", "hazards-filter-segment", "hazards-item-list"],
    "hazardDetail": ["hazard-detail-title-input", "hazard-detail-level-picker", "hazard-detail-status-picker", "hazard-detail-owner-input", "hazard-detail-deadline-picker", "hazard-detail-photo-picker", "hazard-detail-save-button", "hazard-detail-delete-button"],
    "contacts": ["contacts-add-button", "contacts-search-input", "contacts-item-list"],
    "contactDetail": ["contact-detail-name-input", "contact-detail-phone-input", "contact-detail-role-picker", "contact-detail-call-button", "contact-detail-save-button", "contact-detail-delete-button"]
  },
  "openQuestions": [
    "PhotoService real picker deferred to visual integration (placeholder URI acceptable in headless).",
    "CallService real dial want deferred; headless exposes phone for visual-phase wiring.",
    "PersistenceService.init(context) wiring into EntryAbility deferred to visual integration; DataStore is fully functional in-memory meanwhile."
  ]
}

