// Models.ets
//
// Domain types for 平安扣 Pinankou (headless logic phase).
// Explicit classes/enums only — no `any`, no spreads, no dynamic indexed access.

export const enum SafetyLevelValue {
  LOW = 'low',
  MEDIUM = 'medium',
  HIGH = 'high'
}

export const enum HazardStatusValue {
  PENDING = 'pending',
  IN_PROGRESS = 'in_progress',
  RECTIFIED = 'rectified',
  OVERDUE = 'overdue'
}

export const enum PatrolPointStatusValue {
  PENDING = 'pending',
  CHECKED = 'checked',
  ABNORMAL = 'abnormal'
}

export type SafetyLevel = SafetyLevelValue;
export type HazardStatus = HazardStatusValue;
export type PatrolPointStatus = PatrolPointStatusValue;

export class SafetyItem {
  id: string = '';
  title: string = '';
  description: string = '';
  level: SafetyLevel = SafetyLevelValue.MEDIUM;
  owner: string = '';
  completed: boolean = false;
  createdAt: number = 0;
  updatedAt: number = 0;

  constructor(id: string, title: string, level: SafetyLevel, owner: string) {
    this.id = id;
    this.title = title;
    this.level = level;
    this.owner = owner;
    const now: number = currentTimeMillis();
    this.createdAt = now;
    this.updatedAt = now;
  }
}

export class Hazard {
  id: string = '';
  title: string = '';
  description: string = '';
  level: SafetyLevel = SafetyLevelValue.MEDIUM;
  location: string = '';
  photoUri: string = '';
  owner: string = '';
  deadline: number = 0;
  status: HazardStatus = HazardStatusValue.PENDING;
  note: string = '';
  createdAt: number = 0;
  updatedAt: number = 0;

  constructor(id: string, title: string, level: SafetyLevel, owner: string, deadline: number) {
    this.id = id;
    this.title = title;
    this.level = level;
    this.owner = owner;
    this.deadline = deadline;
    const now: number = currentTimeMillis();
    this.createdAt = now;
    this.updatedAt = now;
  }
}

export class PatrolPoint {
  id: string = '';
  name: string = '';
  location: string = '';
  status: PatrolPointStatus = PatrolPointStatusValue.PENDING;
  checkedAt: number = 0;

  constructor(id: string, name: string, location: string) {
    this.id = id;
    this.name = name;
    this.location = location;
  }
}

export class PatrolTask {
  id: string = '';
  title: string = '';
  points: PatrolPoint[] = [];
  createdAt: number = 0;

  constructor(id: string, title: string) {
    this.id = id;
    this.title = title;
    this.createdAt = currentTimeMillis();
  }
}

export class EmergencyContact {
  id: string = '';
  name: string = '';
  phone: string = '';
  role: string = '';

