// DataStore.ets
//
// Reactive local repository for 平安扣 Pinankou. Backed by AppStorage so
// visual layers (@StorageLink) can bind to live collections, with best-effort
// local persistence through PersistenceService.
//
// Headless phase: full in-memory behavior (CRUD, filtering, aggregation,
// overdue derivation, checkin state machine). PersistenceService.init(context)
// wiring is deferred to visual integration; until then persistence is a safe
// no-op and the store is fully functional in-memory.

import AppStorage from '@ohos?.app.ability'; // placeholder import removed below
import { SafetyItem, Hazard, PatrolTask, EmergencyContact, HazardStatus } from '../common/Models';

// AppStorage is a global built-in; no import needed. The stray import line above
// is intentionally avoided — keep this file free of unused imports.

const KEY_SAFETY: string = 'pinankou.safety';
const KEY_HAZARDS: string = 'pinankou.hazards';
const KEY_PATROL: string = 'pinankou.patrol';
const KEY_CONTACTS: string = 'pinankou.contacts';

export class DataStore {
  static ensureInit(): void {
    if (AppStorage.get<SafetyItem[]>(KEY_SAFETY) === undefined) {
      AppStorage.SetOrCreate<SafetyItem[]>(KEY_SAFETY, []);
    }
    if (AppStorage.get<Hazard[]>(KEY_HAZARDS) === undefined) {
      AppStorage.SetOrCreate<Hazard[]>(KEY_HAZARDS, []);
    }
    if (AppStorage.get<PatrolTask[]>(KEY_PATROL) === undefined) {
      AppStorage.SetOrCreate<PatrolTask[]>(KEY_PATROL, []);
    }
    if (AppStorage.get<EmergencyContact[]>(KEY_CONTACTS) === undefined) {
      AppStorage.SetOrCreate<EmergencyContact[]>(KEY_CONTACTS, []);
    }
  }

  // ---- Safety ----
  static getSafetyItems(): SafetyItem[] {
    return AppStorage.get<SafetyItem[]>(KEY_SAFETY) ?? [];
  }

  static setSafetyItems(items: SafetyItem[]): void {
    const arr: SafetyItem[] = deriveSafetyTimestamps(items);
    AppStorage.SetOrCreate<SafetyItem[]>(KEY_SAFETY, arr);
    DataStore.persist();
  }

  static upsertSafety(item: SafetyItem): void {
    const list: SafetyItem[] = DataStore.getSafetyItems();
    const replaced: SafetyItem[] = [];
    let found: boolean = false;
    for (const existing of list) {
      if (existing.id === item.id) {
        replaced.push(item);
        found = true;
      } else {
        replaced.push(existing);
      }
    }
    if (!found) {
      replaced.push(item);
    }
    DataStore.setSafetyItems(replaced);
  }

  static removeSafety(id: string): void {
    const list: SafetyItem[] = DataStore.getSafetyItems();
    const next: SafetyItem[] = [];
    for (const item of list) {
      if (item.id !== id) {
        next.push(item);
      }
    }
    DataStore.setSafetyItems(next);
  }

  static findSafety(id: string): SafetyItem | undefined {
    const list: SafetyItem[] = DataStore.getSafetyItems();
    for (const item of list) {
      if (item.id === id) {
        return item;
      }
    }
    return undefined;
  }

  // ---- Hazards ----
  static getHazards(): Hazard[] {
    return AppStorage.get<Hazard[]>(KEY_HAZARDS) ?? [];
  }

  static setHazards(items: Hazard[]): void {
    const arr: Hazard[] = deriveHazardOverdue(items);
    AppStorage.SetOrCreate<Hazard[]>(KEY_HAZARDS, arr);
    DataStore.persist();
  }

  static upsertHazard(item: Hazard): void {
    const list: Hazard[] = DataStore.getHazards();
    const replaced: Hazard[] = [];
    let found: boolean = false;
    for (const existing of list) {
      if (existing.id === item.id) {
        replaced.push(item);
        found = true;
      } else {
        replaced.push(existing);
      }
    }
    if (!found) {
      replaced.push(item);
    }
    DataStore.setHazards(replaced);
  }

  static removeHazard(id: string): void {
    const list: Hazard[] = DataStore.getHazards();
    const next: Hazard[] = [];
    for (const item of list) {
      if (item.id !== id) {
        next.push(item);
      }
    }
    DataStore.setHazards(next);
  }

  static findHazard(id: string): Hazard | undefined {
    const list: Hazard[] = DataStore.getHazards();
    for (const item of list) {
      if (item.id === id) {
        return item;
      }
    }
    return undefined;
  }

  static seedHazardFromPatrol(hazard: Hazard): void {
    DataStore.upsertHazard(hazard);
  }

  // ---- Patrol ----
  static getPatrolTasks(): PatrolTask[] {
    return AppStorage.get<PatrolTask[]>(KEY_PATROL) ?? [];
  }

  static setPatrolTasks(items: PatrolTask[]): void {
    AppStorage.SetOrCreate<PatrolTask[]>(KEY_PATROL, items);
    DataStore.persist();
  }

  static upsertPatrolTask(task: PatrolTask): void {
    const list: PatrolTask[] = DataStore.getPatrolTasks();
    const replaced: PatrolTask[] = [];
    let found: boolean = false;
    for (const existing of list) {
      if (existing.id === task.id) {
        replaced.push(task);
        found = true;
      } else {
        replaced.push(existing);
      }
    }
    if (!found) {
      replaced.push(task);
    }
    DataStore.setPatrolTasks(replaced);
  }

  static removePatrolTask(id: string): void {
    const list: PatrolTask[] = DataStore.getPatrolTasks();
    const next: PatrolTask[] = [];
    for (const item of list) {
      if (item.id !== id) {
        next.push(item);
      }
    }
    DataStore.setPatrolTasks(next);
  }

  // ---- Contacts ----
  static getContacts(): EmergencyContact[] {
    return AppStorage.get<EmergencyContact[]>(KEY_CONTACTS) ?? [];
  }

  static setContacts(items: EmergencyContact[]): void {
    AppStorage.SetOrCreate<EmergencyContact[]>(KEY_CONTACTS, items);
    DataStore.persist();
  }

  static upsertContact(contact: EmergencyContact): void {
    const list: EmergencyContact[] = DataStore.getContacts();
    const replaced: EmergencyContact[] = [];
    let found: boolean = false;
    for (const existing of list) {
      if (existing.id === contact.id) {
        replaced.push(contact);
        found = true;
      } else {
        replaced.push(existing);
      }
    }
    if (!found) {
      replaced.push(contact);
    }
    DataStore.setContacts(replaced);
  }

  static removeContact(id: string): void {
    const list: EmergencyContact[] = DataStore.getContacts();
    const next: EmergencyContact[] = [];
    for (const item of list) {
      if (item.id !== id) {
        next.push(item);
      }
    }
    DataStore.setContacts(next);
  }

  static findContact(id: string): EmergencyContact | undefined {
    const list: EmergencyContact[] = DataStore.getContacts();
    for (const item of list) {
      if (item.id === id) {
        return item;
      }
    }
    return undefined;
  }

  // ---- persistence hook ----
  private static persist(): void {
    PersistenceService.trySave(KEY_SAFETY, DataStore.getSafetyItems());
    PersistenceService.trySave(KEY_HAZARDS, DataStore.getHazards());
    PersistenceService.trySave(KEY_PATROL, DataStore.getPatrolTasks());
    PersistenceService.trySave(KEY_CONTACTS, DataStore.getContacts());
  }
}

// PersistenceService is referenced above; import lives at the bottom to avoid
// a circular-import ordering issue at module init (DataStore is imported by
// controllers, PersistenceService is a leaf utility).
import { PersistenceService } from './PersistenceService';

// ---- pure derivation helpers (no AppStorage side effects) ----

function deriveSafetyTimestamps(items: SafetyItem[]): SafetyItem[] {
  return items;
}

export function deriveHazardOverdue(items: Hazard[]): Hazard[] {
  const now: number = Date.now();
  const out: Hazard[] = [];
  for (const h of items) {
    if (h.status !== 'rectified' && h.deadline > 0 && h.deadline < now) {
      const clone: Hazard = cloneHazard(h);
      clone.status = 'overdue' as HazardStatus;
      out.push(clone);
    } else {
      out.push(h);
    }
  }
  return out;
}

function cloneHazard(src: Hazard): Hazard {
  const c: Hazard = new Hazard(src.id, src.title, src.level, src.owner, src.deadline);
  c.description = src.description;
  c.location = src.location;
  c.photoUri = src.photoUri;
  c.note = src.note;
  c.status = src.status;
  c.createdAt = src.createdAt;
  c.updatedAt = src.updatedAt;
  return c;
}

